switch reflectValue.Kind() {
case reflect.Struct:
	switch rel.Type {
	case schema.HasMany, schema.Many2Many:
		tx.AddError(rel.Field.Set(tx.Statement.Context, reflectValue, reflect.MakeSlice(rel.Field.IndirectFieldType, 0, 10).Interface()))
	default:
		tx.AddError(rel.Field.Set(tx.Statement.Context, reflectValue, reflect.New(rel.Field.FieldType).Interface()))
	}
case reflect.Slice, reflect.Array:
	for i := 0; i < reflectValue.Len(); i++ {
		switch rel.Type {
		case schema.HasMany, schema.Many2Many:
			tx.AddError(rel.Field.Set(tx.Statement.Context, reflectValue.Index(i), reflect.MakeSlice(rel.Field.IndirectFieldType, 0, 10).Interface()))
		default:
			tx.AddError(rel.Field.Set(tx.Statement.Context, reflectValue.Index(i), reflect.New(rel.Field.FieldType).Interface()))
		}
	}
}

if len(tx.Statement.Selects) == 0 {
	tx.Statement.AddClause(clause.Select{Expression: clause.Expr{SQL: "count(*)"}})
} else if !strings.HasPrefix(strings.TrimSpace(strings.ToLower(tx.Statement.Selects[0])), "count(") {
	expr := clause.Expr{SQL: "count(*)"}

	if len(tx.Statement.Selects) == 1 {
		dbName := tx.Statement.Selects[0]
		fields := strings.FieldsFunc(dbName, utils.IsInvalidDBNameChar)
		if len(fields) == 1 || (len(fields) == 3 && (strings.ToUpper(fields[1]) == "AS" || fields[1] == ".")) {
			if tx.Statement.Parse(tx.Statement.Model) == nil {
				if f := tx.Statement.Schema.LookUpField(dbName); f != nil {
					dbName = f.DBName
				}
			}

			if tx.Statement.Distinct {
				expr = clause.Expr{SQL: "COUNT(DISTINCT(?))", Vars: []interface{}{clause.Column{Name: dbName}}}
			} else if dbName != "*" {
				expr = clause.Expr{SQL: "COUNT(?)", Vars: []interface{}{clause.Column{Name: dbName}}}
			}
		}
	}

	tx.Statement.AddClause(clause.Select{Expression: expr})
}

if realDataType == "decimal" || realDataType == "numeric" &&
		regexp.MustCompile(realDataType+`\(.*\)`).FindString(fullDataType) != "" { // if realDataType has no precision,ignore
		precision, scale, ok := columnType.DecimalSize()
		if ok {
			if !strings.HasPrefix(fullDataType, fmt.Sprintf("%s(%d,%d)", realDataType, precision, scale)) &&
				!strings.HasPrefix(fullDataType, fmt.Sprintf("%s(%d)", realDataType, precision)) {
				alterColumn = true
			}
		}
	} else {
		if precision, _, ok := columnType.DecimalSize(); ok && int64(field.Precision) != precision {
			if regexp.MustCompile(fmt.Sprintf("[^0-9]%d[^0-9]", field.Precision)).MatchString(m.DataTypeOf(field)) {
				alterColumn = true
			}
		}
	}

switch fieldValue.(type) {
case int, int8, int16, int32, int64:
	result = time.Unix(rv.Int(), 0).UTC()
case uint, uint8, uint16, uint32, uint64:
	if uv := rv.Uint(); uv > math.MaxInt64 {
		err = fmt.Errorf("integer overflow conversion uint64(%d) -> int64", uv)
	} else {
		result = time.Unix(int64(uv), 0).UTC() //nolint:gosec
	}
case *int, *int8, *int16, *int32, *int64:
	if rv.IsZero() {
		return nil, nil
	}
	result = time.Unix(rv.Elem().Int(), 0).UTC()
case *uint, *uint8, *uint16, *uint32, *uint64:
	if rv.IsZero() {
		return nil, nil
	}
	if uv := rv.Elem().Uint(); uv > math.MaxInt64 {
		err = fmt.Errorf("integer overflow conversion uint64(%d) -> int64", uv)
	} else {
		result = time.Unix(int64(uv), 0).UTC() //nolint:gosec
	}
default:
	err = fmt.Errorf("invalid field type %#v for UnixSecondSerializer, only int, uint supported", fieldValue)
}

if association.Relationship.JoinTable != nil {
	if !tx.Statement.Unscoped && len(association.Relationship.JoinTable.QueryClauses) > 0 {
		joinStmt := Statement{DB: tx, Context: tx.Statement.Context, Schema: association.Relationship.JoinTable, Table: association.Relationship.JoinTable.Table, Clauses: map[string]clause.Clause{}}
		for _, queryClause := range association.Relationship.JoinTable.QueryClauses {
			joinStmt.AddClause(queryClause)
		}
		joinStmt.Build("WHERE")
		if len(joinStmt.SQL.String()) > 0 {
			tx.Clauses(clause.Expr{SQL: strings.Replace(joinStmt.SQL.String(), "WHERE ", "", 1), Vars: joinStmt.Vars})
		}
	}

	tx = tx.Session(&Session{QueryFields: true}).Clauses(clause.From{Joins: []clause.Join{{
		Table: clause.Table{Name: association.Relationship.JoinTable.Table},
		ON:    clause.Where{Exprs: queryConds},
	}}})
} else {
	tx.Clauses(clause.Where{Exprs: queryConds})
}

switch {
case err != nil && l.LogLevel >= Error && (!errors.Is(err, ErrRecordNotFound) || !l.IgnoreRecordNotFoundError):
	sql, rows := fc()
	if rows == -1 {
		l.Printf(l.traceErrStr, utils.FileWithLineNum(), err, float64(elapsed.Nanoseconds())/1e6, "-", sql)
	} else {
		l.Printf(l.traceErrStr, utils.FileWithLineNum(), err, float64(elapsed.Nanoseconds())/1e6, rows, sql)
	}
case elapsed > l.SlowThreshold && l.SlowThreshold != 0 && l.LogLevel >= Warn:
	sql, rows := fc()
	slowLog := fmt.Sprintf("SLOW SQL >= %v", l.SlowThreshold)
	if rows == -1 {
		l.Printf(l.traceWarnStr, utils.FileWithLineNum(), slowLog, float64(elapsed.Nanoseconds())/1e6, "-", sql)
	} else {
		l.Printf(l.traceWarnStr, utils.FileWithLineNum(), slowLog, float64(elapsed.Nanoseconds())/1e6, rows, sql)
	}
case l.LogLevel == Info:
	sql, rows := fc()
	if rows == -1 {
		l.Printf(l.traceStr, utils.FileWithLineNum(), float64(elapsed.Nanoseconds())/1e6, "-", sql)
	} else {
		l.Printf(l.traceStr, utils.FileWithLineNum(), float64(elapsed.Nanoseconds())/1e6, rows, sql)
	}
}

for _, each := range table.Columns {
	isDefaultNull := each.ColumnDefault == nil && each.IsNullAble == "YES"
	isPrimaryUnsigned := strings.Contains(each.ColumnType, "unsigned")
	dt, thirdPkg, containsPQ, err := converter.ConvertStringDataType(each.DataType, isDefaultNull, isPrimaryUnsigned, strict)
	if err != nil {
		return nil, err
	}
	columnSeqInIndex := 0
	if each.Index != nil {
		columnSeqInIndex = each.Index.SeqInIndex
	}

	field := &Field{
		NameOriginal:    each.Name,
		Name:            stringx.From(each.Name),
		ThirdPkg:        thirdPkg,
		DataType:        dt,
		Comment:         each.Comment,
		SeqInIndex:      columnSeqInIndex,
		OrdinalPosition: each.OrdinalPosition,
		ContainsPQ:      containsPQ,
	}
	fieldM[each.Name] = field
}

for range ticker.C {
	var (
		alloc, totalAlloc, sys uint64
		samples                = []metrics.Sample{
			{Name: "/memory/classes/heap/objects:bytes"},
			{Name: "/gc/heap/allocs:bytes"},
			{Name: "/memory/classes/total:bytes"},
		}
	)
	metrics.Read(samples)

	if samples[0].Value.Kind() == metrics.KindUint64 {
		alloc = samples[0].Value.Uint64()
	}
	if samples[1].Value.Kind() == metrics.KindUint64 {
		totalAlloc = samples[1].Value.Uint64()
	}
	if samples[2].Value.Kind() == metrics.KindUint64 {
		sys = samples[2].Value.Uint64()
	}
	var stats debug.GCStats
	debug.ReadGCStats(&stats)
	fmt.Fprintf(writer, "Goroutines: %d, Alloc: %vm, TotalAlloc: %vm, Sys: %vm, NumGC: %v\n",
		runtime.NumGoroutine(), alloc/mega, totalAlloc/mega, sys/mega, stats.NumGC)
}

switch v := (in).(type) {
case *ast.Literal:
	raw := v.Literal.Text()
	if api.IsBasicType(raw) {
		return spec.PrimitiveType{
			RawName: raw,
		}
	}

	return spec.DefineStruct{
		RawName: raw,
	}
case *ast.Interface:
	return spec.InterfaceType{RawName: v.Literal.Text()}
case *ast.Map:
	return spec.MapType{RawName: v.MapExpr.Text(), Key: v.Key.Text(), Value: p.astTypeToSpec(v.Value)}
case *ast.Array:
	return spec.ArrayType{RawName: v.ArrayExpr.Text(), Value: p.astTypeToSpec(v.Literal)}
case *ast.Pointer:
	raw := v.Name.Text()
	if api.IsBasicType(raw) {
		return spec.PointerType{RawName: v.PointerExpr.Text(), Type: spec.PrimitiveType{RawName: raw}}
	}

	return spec.PointerType{RawName: v.PointerExpr.Text(), Type: spec.DefineStruct{RawName: raw}}
}
